import { useState } from "react";
import api from "../services/api";
import { useNavigate } from "react-router-dom";

export default function QuestionForm() {
  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [tagInput, setTagInput] = useState("");
  const [tags, setTags] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleTagKeyDown = (e) => {
    if (["Enter", ",", "Tab"].includes(e.key)) {
      e.preventDefault();
      const val = tagInput.trim().toLowerCase().replace(/[^a-z0-9.\-+#]/g, "");
      if (val && !tags.includes(val) && tags.length < 6) {
        setTags([...tags, val]);
      }
      setTagInput("");
    }
    if (e.key === "Backspace" && !tagInput && tags.length) {
      setTags(tags.slice(0, -1));
    }
  };

  const removeTag = (t) => setTags(tags.filter((x) => x !== t));

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title.trim() || !body.trim()) {
      setError("Title and body are required.");
      return;
    }
    setIsLoading(true);
    setError("");
    try {
      await api.post(
        "/questions",
        { title: title.trim(), body: body.trim(), tags },
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      navigate("/");
    } catch (err) {
      setError(err?.response?.data?.message || "Submission failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const charLimit = 10000;
  const bodyPct = Math.min((body.length / charLimit) * 100, 100);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Share+Tech+Mono&display=swap');

        .qf { font-family: 'Share Tech Mono', monospace; display: flex; flex-direction: column; gap: 28px; }

        /* Field group */
        .qf-field { display: flex; flex-direction: column; gap: 8px; }

        .qf-label {
          display: flex; align-items: center; gap: 8px;
          font-size: 9px; letter-spacing: 0.28em; text-transform: uppercase;
          color: rgba(0,255,200,0.5);
        }
        .qf-label-dash { width: 18px; height: 1px; background: rgba(0,255,200,0.35); }
        .qf-label-req { color: rgba(0,255,200,0.3); margin-left: 2px; }

        .qf-hint {
          font-size: 10px; color: rgba(255,255,255,0.25);
          letter-spacing: 0.04em; line-height: 1.5;
          margin-top: -4px;
        }

        /* Input / Textarea shared */
        .qf-input-wrap { position: relative; }

        .qf-input-wrap::after {
          content: '';
          position: absolute; bottom: 0; left: 0;
          height: 1px; width: 0;
          background: linear-gradient(90deg, #00ffc8, #00c8ff);
          box-shadow: 0 0 8px #00ffc8;
          transition: width 0.35s ease;
          pointer-events: none;
        }
        .qf-input-wrap:focus-within::after { width: 100%; }

        .qf-input, .qf-textarea {
          width: 100%;
          background: rgba(0,255,200,0.03);
          border: 1px solid rgba(0,255,200,0.13);
          color: #e6fff8;
          font-family: 'Share Tech Mono', monospace;
          font-size: 13px;
          padding: 12px 14px;
          outline: none;
          transition: border-color 0.25s, background 0.25s, box-shadow 0.25s;
          border-radius: 0;
          -webkit-appearance: none;
          letter-spacing: 0.03em;
          resize: none;
        }
        .qf-input::placeholder, .qf-textarea::placeholder { color: rgba(0,255,200,0.18); }
        .qf-input:focus, .qf-textarea:focus {
          border-color: rgba(0,255,200,0.5);
          background: rgba(0,255,200,0.05);
          box-shadow: 0 0 22px rgba(0,255,200,0.07), inset 0 0 16px rgba(0,255,200,0.025);
        }

        .qf-textarea { min-height: 200px; line-height: 1.65; }

        /* Textarea footer */
        .qf-textarea-footer {
          display: flex; justify-content: space-between; align-items: center;
          margin-top: 6px;
        }

        .qf-charbar-wrap {
          flex: 1; max-width: 160px; height: 2px;
          background: rgba(0,255,200,0.08); position: relative;
        }
        .qf-charbar {
          position: absolute; left: 0; top: 0; height: 100%;
          background: linear-gradient(90deg, #00ffc8, #00c8ff);
          box-shadow: 0 0 6px rgba(0,255,200,0.5);
          transition: width 0.2s ease;
        }
        .qf-charcount {
          font-size: 10px; color: rgba(0,255,200,0.3);
          letter-spacing: 0.08em;
        }

        /* Tag input */
        .qf-tag-box {
          display: flex; flex-wrap: wrap; align-items: center;
          gap: 7px;
          background: rgba(0,255,200,0.03);
          border: 1px solid rgba(0,255,200,0.13);
          padding: 9px 12px;
          cursor: text;
          transition: border-color 0.25s, background 0.25s, box-shadow 0.25s;
          min-height: 46px;
        }
        .qf-tag-box:focus-within {
          border-color: rgba(0,255,200,0.5);
          background: rgba(0,255,200,0.05);
          box-shadow: 0 0 22px rgba(0,255,200,0.07);
        }

        .qf-tag {
          display: inline-flex; align-items: center; gap: 6px;
          padding: 3px 9px 3px 10px;
          border: 1px solid rgba(0,255,200,0.3);
          background: rgba(0,255,200,0.06);
          font-size: 11px; color: rgba(0,255,200,0.85);
          letter-spacing: 0.06em;
          animation: tag-pop 0.2s ease;
        }

        @keyframes tag-pop {
          from { transform: scale(0.8); opacity: 0; }
          to   { transform: scale(1);   opacity: 1; }
        }

        .qf-tag-remove {
          background: none; border: none; padding: 0;
          color: rgba(0,255,200,0.4); font-size: 13px;
          cursor: pointer; line-height: 1;
          transition: color 0.15s;
        }
        .qf-tag-remove:hover { color: #ff7070; }

        .qf-tag-input {
          flex: 1; min-width: 120px;
          background: none; border: none; outline: none;
          color: #e6fff8; font-family: 'Share Tech Mono', monospace;
          font-size: 13px; letter-spacing: 0.04em;
        }
        .qf-tag-input::placeholder { color: rgba(0,255,200,0.18); }

        .qf-tag-hint {
          font-size: 10px; color: rgba(0,255,200,0.25);
          letter-spacing: 0.08em; margin-top: 6px;
        }

        /* Error */
        .qf-error {
          display: flex; align-items: center; gap: 10px;
          padding: 11px 14px;
          background: rgba(255,60,60,0.07);
          border: 1px solid rgba(255,60,60,0.28);
          font-size: 11px; color: #ff7070;
          letter-spacing: 0.04em;
          opacity: 0; max-height: 0; overflow: hidden;
          transition: opacity 0.3s, max-height 0.3s;
        }
        .qf-error.on { opacity: 1; max-height: 60px; }

        /* Divider */
        .qf-divider {
          height: 1px;
          background: linear-gradient(90deg, rgba(0,255,200,0.12), transparent);
        }

        /* Submit row */
        .qf-submit-row {
          display: flex; align-items: center; justify-content: space-between;
          flex-wrap: wrap; gap: 12px;
        }

        .qf-submit-meta {
          font-size: 10px; color: rgba(0,255,200,0.25);
          letter-spacing: 0.1em;
        }

        .qf-btn {
          display: flex; align-items: center; gap: 10px;
          padding: 14px 32px;
          background: transparent;
          border: 1px solid rgba(0,255,200,0.45);
          color: #00ffc8;
          font-family: 'Orbitron', sans-serif;
          font-size: 11px; font-weight: 700;
          letter-spacing: 0.28em; text-transform: uppercase;
          cursor: pointer; position: relative; overflow: hidden;
          transition: color 0.3s, border-color 0.3s, box-shadow 0.3s;
          border-radius: 0;
        }
        .qf-btn::before {
          content: '';
          position: absolute; inset: 0;
          background: linear-gradient(135deg, rgba(0,255,200,0.12), rgba(0,150,255,0.07));
          opacity: 0; transition: opacity 0.3s;
        }
        .qf-btn:not(:disabled):hover::before { opacity: 1; }
        .qf-btn:not(:disabled):hover {
          border-color: #00ffc8;
          box-shadow: 0 0 32px rgba(0,255,200,0.18);
          color: #fff;
        }
        .qf-btn:disabled { opacity: 0.35; cursor: not-allowed; }

        .qf-load-bar {
          position: absolute; bottom: 0; left: 0;
          height: 2px; width: 100%;
          background: linear-gradient(90deg, transparent, #00ffc8, #00c8ff, transparent);
          animation: lbar 1.4s ease-in-out infinite;
        }
        @keyframes lbar { 0%{transform:translateX(-100%);} 100%{transform:translateX(100%);} }

        .qf-btn-icon { font-size: 14px; }
      `}</style>

      <form className="qf" onSubmit={handleSubmit}>

        {/* Title */}
        <div className="qf-field">
          <label className="qf-label">
            <span className="qf-label-dash" />
            Title
            <span className="qf-label-req">*</span>
          </label>
          <p className="qf-hint">Summarise your problem in one clear sentence.</p>
          <div className="qf-input-wrap">
            <input
              className="qf-input"
              type="text"
              value={title}
              onChange={(e) => { setTitle(e.target.value); setError(""); }}
              placeholder="e.g. How do I reverse a linked list in Python?"
              maxLength={150}
            />
          </div>
        </div>

        {/* Body */}
        <div className="qf-field">
          <label className="qf-label">
            <span className="qf-label-dash" />
            Body
            <span className="qf-label-req">*</span>
          </label>
          <p className="qf-hint">Include all context — code snippets, errors, and what you've tried.</p>
          <div className="qf-input-wrap">
            <textarea
              className="qf-textarea"
              value={body}
              onChange={(e) => { setBody(e.target.value); setError(""); }}
              placeholder="Describe your problem in detail..."
              maxLength={charLimit}
            />
          </div>
          <div className="qf-textarea-footer">
            <div className="qf-charbar-wrap">
              <div className="qf-charbar" style={{ width: `${bodyPct}%` }} />
            </div>
            <span className="qf-charcount">{body.length} / {charLimit.toLocaleString()}</span>
          </div>
        </div>

        {/* Tags */}
        <div className="qf-field">
          <label className="qf-label">
            <span className="qf-label-dash" />
            Tags
          </label>
          <p className="qf-hint">Up to 6 tags. Press Enter or comma to add.</p>
          <div
            className="qf-tag-box"
            onClick={(e) => e.currentTarget.querySelector("input")?.focus()}
          >
            {tags.map((t) => (
              <span className="qf-tag" key={t}>
                {t}
                <button
                  type="button"
                  className="qf-tag-remove"
                  onClick={() => removeTag(t)}
                  aria-label={`Remove ${t}`}
                >×</button>
              </span>
            ))}
            <input
              className="qf-tag-input"
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              onKeyDown={handleTagKeyDown}
              placeholder={tags.length === 0 ? "python, react, sql…" : ""}
              disabled={tags.length >= 6}
            />
          </div>
          {tags.length >= 6 && (
            <span className="qf-tag-hint">Maximum tags reached.</span>
          )}
        </div>

        <div className="qf-divider" />

        {/* Error */}
        <div className={`qf-error ${error ? "on" : ""}`}>
          <span style={{ fontSize: 15 }}>⚠</span>
          <span>{error}</span>
        </div>

        {/* Submit */}
        <div className="qf-submit-row">
          <span className="qf-submit-meta">
            {title.length > 0 || body.length > 0
              ? `${[title && "title", body && "body", tags.length && "tags"].filter(Boolean).join(" · ")} ready`
              : "// fill in required fields"}
          </span>
          <button
            className="qf-btn"
            type="submit"
            disabled={isLoading || !title.trim() || !body.trim()}
          >
            {isLoading ? (
              <><span>Submitting</span><div className="qf-load-bar" /></>
            ) : (
              <><span className="qf-btn-icon">▶</span><span>Submit Query</span></>
            )}
          </button>
        </div>

      </form>
    </>
  );
}
